public String shortestPalindrome(String s) {
    int n = s.length();
    String rev_s = new StringBuilder(s).reverse().toString();

    for (int i = 0; i < n; ++i) {
        if(s.substring(0, n - i).equals(rev_s.substring(i)))
            return rev_s.substring(0, i) + s;
    }
    return "";
}
```


